-- ------------------------------------------------------------
-- PDFs originais conhecidos (das fontes oficiais pesquisadas)
-- ------------------------------------------------------------
update funding_opportunities set pdf_url = 'https://pepacc.pt/wp-content/uploads/2025/09/OT_221_-Investimento_05092025_4periodo.pdf'
  where name = 'Prémio Instalação Jovens Agricultores (C.2.2.1)' and (pdf_url is null or pdf_url = '');

update funding_opportunities set pdf_url = 'https://pepacc.pt/wp-content/uploads/2025/08/AVISO_Candidatura_211_Exploracoes-Agricolas_28082025.pdf'
  where name = 'Investimento Produtivo Agrícola — Modernização (C.2.1.1)' and (pdf_url is null or pdf_url = '');

-- ------------------------------------------------------------
-- Regra extra: apoios anteriores afetam "primeira instalação"
-- (usa o novo campo received_aid_before)
-- ------------------------------------------------------------
select id,'Sem apoios agrícolas anteriores','received_aid_before','is_false',null,null,'aviso',
 'Não recebeu apoios antes — coerente com primeira instalação.',
 'Já recebeu apoios agrícolas. Se foi há mais de 2 anos, pode comprometer a primeira instalação. Confirmar datas do Pedido Único.',
 5
from funding_opportunities where name = 'Prémio Instalação Jovens Agricultores (C.2.2.1)';
